#!/usr/bin/env Rscript
#
# retroactive_register_gSSURGO_soils.R
#
# PURPOSE:
#   Retroactively register existing gSSURGO soil.nc files in BETY.
#   These files were generated by the NASA CMS SDA workflow (@para2x) but
#   were never registered because soil_process() skipped dbfile.input.insert()
#   when files already existed on disk (Issue #2666).
#
# USAGE (on BU server):
#   Rscript retroactive_register_gSSURGO_soils.R [<dbfiles_root>]
#
#   <dbfiles_root>  optional path to the folder containing gSSURGO_site_* dirs.
#                   Defaults to /fs/data1/pecan.data/dbfiles if not supplied.
#
# REQUIREMENTS:
#   - Run on a machine with access to /fs/data1/pecan.data/dbfiles
#   - BETY database credentials set in pecan.xml or passed via dbparms below
#   - PEcAn.DB package installed
#
# After running, verify with:
#   SELECT i.id, i.name, d.file_path, d.file_name
#   FROM inputs i JOIN dbfiles d ON d.container_id = i.id
#   WHERE i.name LIKE '%gSSURGO%';
#

library(PEcAn.DB)
library(PEcAn.logger)
library(stringr)

#------------------------------------------------------------------------------
# CONFIGURATION
#------------------------------------------------------------------------------
args         <- commandArgs(trailingOnly = TRUE)
dbfiles_root <- if (length(args) >= 1) args[[1]] else "/fs/data1/pecan.data/dbfiles"
bety_settings <- list(
  driver   = "PostgreSQL",
  user     = "bety",
  password = "bety",
  host     = "localhost",
  dbname   = "bety",
  port     = 5432
)
dry_run <- as.logical(Sys.getenv("DRY_RUN", "TRUE"))   # Set to FALSE to actually write to BETY; TRUE to just preview
#------------------------------------------------------------------------------

PEcAn.logger::logger.setLevel("INFO")

# Open DB connection
if (!dry_run) {
  con <- PEcAn.DB::db.open(bety_settings)
  on.exit(PEcAn.DB::db.close(con), add = TRUE)
} else {
  con <- NULL
}

# Find all gSSURGO_site_* folders
soil_dirs <- list.dirs(dbfiles_root, recursive = FALSE, full.names = TRUE)
soil_dirs <- soil_dirs[grepl("gSSURGO_site_", basename(soil_dirs))]

if (length(soil_dirs) == 0) {
  PEcAn.logger::logger.warn("No gSSURGO_site_* directories found under ", dbfiles_root)
  stop("Nothing to register. Check dbfiles_root path.")
}

PEcAn.logger::logger.info(paste0("Found ", length(soil_dirs), " gSSURGO_site_* directories."))

registered   <- 0
skipped      <- 0
errors       <- 0

for (soil_dir in soil_dirs) {

  # Parse site_id from folder name: gSSURGO_site_<str_ns>
  # str_ns is either "<site_id>" or "<prefix>-<suffix>" for BETYdb IDs
  folder_name <- basename(soil_dir)
  str_ns      <- sub("^gSSURGO_site_", "", folder_name)

  # Reconstruct numeric site_id from str_ns
  if (grepl("^[0-9]+-[0-9]+$", str_ns)) {
    parts   <- as.numeric(strsplit(str_ns, "-")[[1]])
    site_id <- parts[1] * 1e9 + parts[2]
  } else {
    site_id <- as.numeric(str_ns)
  }

  if (is.na(site_id)) {
    PEcAn.logger::logger.warn("Could not parse site_id from folder: ", folder_name, ". Skipping.")
    errors <- errors + 1
    next
  }

  # Find all .nc files in this folder
  nc_files <- list.files(soil_dir, pattern = "\\.nc$", full.names = TRUE)

  if (length(nc_files) == 0) {
    PEcAn.logger::logger.info(paste0("No .nc files in ", folder_name, ". Skipping."))
    skipped <- skipped + 1
    next
  }

  for (nc_file in nc_files) {
    in.path   <- paste0(dirname(nc_file), "/")
    in.prefix <- stringr::str_remove(basename(nc_file), "\\.nc$")

    PEcAn.logger::logger.info(paste0(
      if (dry_run) "[DRY RUN] Would register: " else "Registering: ",
      nc_file, " for site_id=", site_id
    ))

    if (!dry_run) {
      tryCatch({
        PEcAn.DB::dbfile.input.insert(
          in.path,
          in.prefix,
          site_id,
          startdate  = NULL,
          enddate    = NULL,
          mimetype   = "application/x-netcdf",
          formatname = "pecan_soil_standard",
          con        = con,
          ens        = TRUE
        )
        registered <- registered + 1
      }, error = function(e) {
        PEcAn.logger::logger.error(paste0("Failed to register ", nc_file, ": ", e$message))
        errors <<- errors + 1
      })
    } else {
      registered <- registered + 1
    }
  }
}

#------------------------------------------------------------------------------
# Summary
#------------------------------------------------------------------------------
PEcAn.logger::logger.info(paste0(
  "\n===== SUMMARY =====",
  "\n  Directories found : ", length(soil_dirs),
  "\n  Files registered  : ", registered, if (dry_run) " (dry run — not actually written)" else "",
  "\n  Directories skipped (no .nc): ", skipped,
  "\n  Errors            : ", errors,
  "\n===================\n",
  if (dry_run) "\nRe-run with dry_run <- FALSE to actually register files in BETY." else
               "Registration complete. Verify in BETY:\n  SELECT i.id, i.name, d.file_path FROM inputs i JOIN dbfiles d ON d.container_id=i.id WHERE i.name LIKE '%gSSURGO%';"
))
